// Fetch all purchases, products, and customers
const [purchasesResult, productsResult, customersResult] = await Promise.all([
  external_queryTable({ table: 'purchases' }),
  external_queryTable({ table: 'products' }),
  external_queryTable({ table: 'customers' })
]);

const purchases = purchasesResult.rows as any[];
const products = productsResult.rows as any[];
const customers = customersResult.rows as any[];

// Create a map of product ID to category
const productMap = Object.fromEntries(
  products.map(p => [p.id, { name: p.name, category: p.category, price: p.price }])
);

// Group purchases by customer
const customerSpending = new Map<number, { 
  name: string;
  totalSpent: number;
  categorySpending: Record<string, number>;
}>();

customers.forEach(customer => {
  customerSpending.set(customer.id, {
    name: customer.name,
    totalSpent: 0,
    categorySpending: {}
  });
});

// Process purchases
purchases.forEach(purchase => {
  const product = productMap[purchase.product_id];
  const customer = customerSpending.get(purchase.customer_id);

  if (customer && product) {
    customer.totalSpent += purchase.total;
    if (!customer.categorySpending[product.category]) {
      customer.categorySpending[product.category] = 0;
    }
    customer.categorySpending[product.category] += purchase.total;
  }
});

// Convert to array and sort by total spending (descending)
const rankedCustomers = Array.from(customerSpending.values())
  .filter(c => c.totalSpent > 0)  // Only customers with purchases
  .sort((a, b) => b.totalSpent - a.totalSpent)
  .map((customer, rank) => {
    const percentages: Record<string, number> = {};
    const categories = ['Electronics', 'Furniture', 'Office Products'];

    categories.forEach(cat => {
      const categoryTotal = customer.categorySpending[cat] || 0;
      percentages[cat] = customer.totalSpent > 0 
        ? Math.round((categoryTotal / customer.totalSpent) * 100 * 100) / 100
        : 0;
    });

    return {
      rank: rank + 1,
      name: customer.name,
      totalSpent: Math.round(customer.totalSpent * 100) / 100,
      electronics: percentages['Electronics'],
      furniture: percentages['Furniture'],
      officeProducts: percentages['Office Products']
    };
  });

return rankedCustomers;
"}
